from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest, REGISTRY, CONTENT_TYPE_LATEST
from functools import wraps
import time
import random

app = Flask(__name__)

request_count = Counter(
    'http_requests_total',
    'Total HTTP requests',
    ['method', 'endpoint', 'status']
)

request_latency = Histogram(
    'http_request_duration_seconds',
    'HTTP request latency',
    ['method', 'endpoint']
)

in_progress_requests = Gauge(
    'http_requests_in_progress',
    'Number of HTTP requests in progress',
    ['method', 'endpoint']
)

active_users = Gauge(
    'active_users',
    'Number of active users'
)

order_total = Counter(
    'orders_total',
    'Total number of orders',
    ['status']
)

order_value = Histogram(
    'order_value_dollars',
    'Order value in dollars',
    buckets=[10, 50, 100, 500, 1000, 5000]
)

inventory_items = Gauge(
    'inventory_items',
    'Number of items in inventory',
    ['product']
)

database_connections = Gauge(
    'database_connections_active',
    'Number of active database connections'
)

cache_hits = Counter(
    'cache_hits_total',
    'Total number of cache hits'
)

cache_misses = Counter(
    'cache_misses_total',
    'Total number of cache misses'
)

error_count = Counter(
    'errors_total',
    'Total number of errors',
    ['error_type']
)

def track_metrics(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        method = request.method
        endpoint = request.endpoint or 'unknown'
        
        in_progress_requests.labels(method=method, endpoint=endpoint).inc()
        
        start_time = time.time()
        
        try:
            response = f(*args, **kwargs)
            
            if isinstance(response, tuple):
                status_code = response[1]
            else:
                status_code = 200
            
            request_count.labels(
                method=method,
                endpoint=endpoint,
                status=status_code
            ).inc()
            
            return response
            
        except Exception as e:
            error_count.labels(error_type=type(e).__name__).inc()
            request_count.labels(
                method=method,
                endpoint=endpoint,
                status=500
            ).inc()
            raise
            
        finally:
            duration = time.time() - start_time
            request_latency.labels(method=method, endpoint=endpoint).observe(duration)
            in_progress_requests.labels(method=method, endpoint=endpoint).dec()
    
    return decorated_function


@app.route('/metrics')
def metrics():
    return generate_latest(REGISTRY), 200, {'Content-Type': CONTENT_TYPE_LATEST}


@app.route('/')
@track_metrics
def index():
    return jsonify({'message': 'Welcome to the Flask Prometheus Demo'}), 200


@app.route('/health')
@track_metrics
def health():
    return jsonify({'status': 'healthy'}), 200


@app.route('/users/login', methods=['POST'])
@track_metrics
def login():
    active_users.inc()
    return jsonify({'message': 'User logged in'}), 200


@app.route('/users/logout', methods=['POST'])
@track_metrics
def logout():
    active_users.dec()
    return jsonify({'message': 'User logged out'}), 200


@app.route('/orders', methods=['POST'])
@track_metrics
def create_order():
    order_data = request.get_json() or {}
    order_amount = order_data.get('amount', random.uniform(10, 1000))
    status = order_data.get('status', 'completed')
    
    order_total.labels(status=status).inc()
    order_value.observe(order_amount)
    
    return jsonify({
        'message': 'Order created',
        'amount': order_amount,
        'status': status
    }), 201


@app.route('/inventory/<product>')
@track_metrics
def get_inventory(product):
    quantity = random.randint(0, 100)
    inventory_items.labels(product=product).set(quantity)
    
    return jsonify({
        'product': product,
        'quantity': quantity
    }), 200


@app.route('/inventory/<product>', methods=['PUT'])
@track_metrics
def update_inventory(product):
    data = request.get_json() or {}
    quantity = data.get('quantity', random.randint(0, 100))
    inventory_items.labels(product=product).set(quantity)
    
    return jsonify({
        'product': product,
        'quantity': quantity
    }), 200


@app.route('/cache/<key>')
@track_metrics
def cache_lookup(key):
    hit = random.choice([True, False])
    
    if hit:
        cache_hits.inc()
        return jsonify({'key': key, 'value': 'cached_value', 'hit': True}), 200
    else:
        cache_misses.inc()
        return jsonify({'key': key, 'hit': False}), 404


@app.route('/database/connections')
@track_metrics
def db_connections():
    connections = random.randint(5, 50)
    database_connections.set(connections)
    
    return jsonify({'active_connections': connections}), 200


@app.route('/error')
@track_metrics
def trigger_error():
    error_type = request.args.get('type', 'generic')
    
    if error_type == 'value':
        raise ValueError('Simulated value error')
    elif error_type == 'type':
        raise TypeError('Simulated type error')
    else:
        raise Exception('Simulated generic error')


@app.route('/slow')
@track_metrics
def slow_endpoint():
    delay = float(request.args.get('delay', 2.0))
    time.sleep(delay)
    return jsonify({'message': f'Delayed for {delay} seconds'}), 200


